impl From<liter_llm::types::BatchStatus> for JsBatchStatus {
    fn from(val: liter_llm::types::BatchStatus) -> Self {
        match val {
            liter_llm::types::BatchStatus::Validating => Self::Validating,
            liter_llm::types::BatchStatus::Failed => Self::Failed,
            liter_llm::types::BatchStatus::InProgress => Self::InProgress,
            liter_llm::types::BatchStatus::Finalizing => Self::Finalizing,
            liter_llm::types::BatchStatus::Completed => Self::Completed,
            liter_llm::types::BatchStatus::Expired => Self::Expired,
            liter_llm::types::BatchStatus::Cancelling => Self::Cancelling,
            liter_llm::types::BatchStatus::Cancelled => Self::Cancelled,
        }
    }
}

impl From<liter_llm::provider::custom::AuthHeaderFormat> for JsAuthHeaderFormat {
    fn from(val: liter_llm::provider::custom::AuthHeaderFormat) -> Self {
        match val {
            liter_llm::provider::custom::AuthHeaderFormat::Bearer => Self::Bearer,
            liter_llm::provider::custom::AuthHeaderFormat::ApiKey(..) => Self::ApiKey,
            liter_llm::provider::custom::AuthHeaderFormat::None => Self::None,
        }
    }
}

