/// Convert a `liter_llm::error::LiterLlmError` error to a NAPI error.
#[allow(dead_code)]
fn liter_llm_error_to_napi_err(e: liter_llm::error::LiterLlmError) -> napi::Error {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        liter_llm::error::LiterLlmError::Authentication { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Authentication] {}", msg))
        }
        liter_llm::error::LiterLlmError::RateLimited { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[RateLimited] {}", msg))
        }
        liter_llm::error::LiterLlmError::BadRequest { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[BadRequest] {}", msg))
        }
        liter_llm::error::LiterLlmError::ContextWindowExceeded { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ContextWindowExceeded] {}", msg))
        }
        liter_llm::error::LiterLlmError::ContentPolicy { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ContentPolicy] {}", msg))
        }
        liter_llm::error::LiterLlmError::NotFound { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[NotFound] {}", msg))
        }
        liter_llm::error::LiterLlmError::ServerError { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ServerError] {}", msg))
        }
        liter_llm::error::LiterLlmError::ServiceUnavailable { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ServiceUnavailable] {}", msg))
        }
        liter_llm::error::LiterLlmError::Timeout => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Timeout] {}", msg))
        }
        liter_llm::error::LiterLlmError::Streaming { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Streaming] {}", msg))
        }
        liter_llm::error::LiterLlmError::EndpointNotSupported { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[EndpointNotSupported] {}", msg))
        }
        liter_llm::error::LiterLlmError::InvalidHeader { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[InvalidHeader] {}", msg))
        }
        liter_llm::error::LiterLlmError::Serialization(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Serialization] {}", msg))
        }
        liter_llm::error::LiterLlmError::BudgetExceeded { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[BudgetExceeded] {}", msg))
        }
        liter_llm::error::LiterLlmError::HookRejected { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[HookRejected] {}", msg))
        }
        liter_llm::error::LiterLlmError::InternalError { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[InternalError] {}", msg))
        }
        _ => napi::Error::new(napi::Status::GenericFailure, msg),
    }
}
